/**
 * User notification preferences model.
 *
 * Preferences are organized by notification category (not individual type).
 * Each NotificationType maps to a NotificationCategory, allowing users to
 * subscribe/unsubscribe from groups of related notifications.
 *
 * Currently supports email channel settings. Additional channels can be
 * added to UserPreferences without restructuring.
 */

import type { NotificationType } from './notification.js';

/**
 * Notification categories that users can subscribe to.
 * Categories group related notification types for easier preference management.
 */
export type NotificationCategory = 'order-updates' | 'account';

/**
 * Maps each notification type to its category.
 */
export const notificationTypeToCategory: Record<NotificationType, NotificationCategory> = {
  'order-confirmation': 'order-updates',
  'order-status-update': 'order-updates',
  'welcome': 'account',
  'user-updated': 'account',
};

/**
 * All available notification categories.
 */
export const allCategories: NotificationCategory[] = ['order-updates', 'account'];

/**
 * How frequently email notifications are delivered.
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest' | 'none';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Whether email notifications are enabled at all */
  enabled: boolean;
  /** Delivery frequency */
  frequency: EmailFrequency;
  /** Which notification categories the user is subscribed to */
  subscribedCategories: NotificationCategory[];
}

/**
 * Full user notification preferences.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences.
 */
export interface CreateUserPreferencesInput {
  userId: string;
  email?: Partial<EmailPreferences>;
}

/**
 * Input for updating user preferences.
 */
export interface UpdateUserPreferencesInput {
  email?: Partial<EmailPreferences>;
}

/**
 * Returns default email preferences: enabled, immediate delivery, all categories.
 */
export function getDefaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: [...allCategories],
  };
}

/**
 * Returns default user preferences for a given user ID.
 */
export function getDefaultUserPreferences(userId: string): UserPreferences {
  return {
    id: `prefs-${userId}`,
    userId,
    email: getDefaultEmailPreferences(),
    createdAt: new Date(),
    updatedAt: new Date(),
  };
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preference-specific query methods.
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences, NotificationCategory } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as UserPreferences['email']['frequency'],
        subscribedCategories: JSON.parse(record['emailSubscribedCategories'] as string) as NotificationCategory[],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailSubscribedCategories: JSON.stringify(entity.email.subscribedCategories),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user preferences and a method to check
 * whether a notification should be sent based on user settings.
 *
 * Depends on:
 * - PreferencesRepository for data access
 * - UserPreferences model for types and defaults
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { NotificationType } from '../models/notification.js';
import type {
  UserPreferences,
  CreateUserPreferencesInput,
  UpdateUserPreferencesInput,
  NotificationCategory,
} from '../models/user-preferences.js';
import {
  getDefaultUserPreferences,
  getDefaultEmailPreferences,
  notificationTypeToCategory,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private repository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns defaults if none exist.
   */
  getPreferences(userId: string): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return getDefaultUserPreferences(userId);
  }

  /**
   * Create preferences for a user.
   * Throws if preferences already exist for this user.
   */
  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(input.userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${input.userId}`);
    }

    const defaults = getDefaultEmailPreferences();
    const emailPrefs = input.email
      ? {
          enabled: input.email.enabled ?? defaults.enabled,
          frequency: input.email.frequency ?? defaults.frequency,
          subscribedCategories: input.email.subscribedCategories ?? [...defaults.subscribedCategories],
        }
      : defaults;

    const prefs: UserPreferences = {
      id: `prefs-${input.userId}`,
      userId: input.userId,
      email: emailPrefs,
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    this.logger.info(`Creating preferences for user: ${input.userId}`);
    return this.repository.save(prefs);
  }

  /**
   * Update preferences for a user.
   * Throws if no preferences exist for this user.
   */
  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      throw new Error(`No preferences found for user: ${userId}`);
    }

    const updatedEmail = input.email
      ? {
          enabled: input.email.enabled ?? existing.email.enabled,
          frequency: input.email.frequency ?? existing.email.frequency,
          subscribedCategories: input.email.subscribedCategories ?? [...existing.email.subscribedCategories],
        }
      : existing.email;

    const updated: UserPreferences = {
      ...existing,
      email: updatedEmail,
      updatedAt: new Date(),
    };

    this.logger.info(`Updating preferences for user: ${userId}`);
    return this.repository.update(existing.id, updated);
  }

  /**
   * Delete preferences for a user (resets to defaults).
   */
  deletePreferences(userId: string): boolean {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      return false;
    }
    this.logger.info(`Deleting preferences for user: ${userId}`);
    return this.repository.delete(existing.id);
  }

  /**
   * Check whether a notification should be sent to a user via email.
   *
   * Returns true if:
   * - No preferences exist (default: send all)
   * - Email is enabled AND frequency is not 'none' AND the notification's
   *   category is in the user's subscribed categories
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);

    // No preferences stored — default to sending
    if (!prefs) {
      return true;
    }

    if (!prefs.email.enabled) {
      this.logger.debug(`Email disabled for user: ${userId}`);
      return false;
    }

    if (prefs.email.frequency === 'none') {
      this.logger.debug(`Email frequency set to none for user: ${userId}`);
      return false;
    }

    const category: NotificationCategory = notificationTypeToCategory[notificationType];
    if (!prefs.email.subscribedCategories.includes(category)) {
      this.logger.debug(`User ${userId} not subscribed to category: ${category}`);
      return false;
    }

    return true;
  }
}

